/**
 * @name Thymeleaf template injection via user-controlled input
 * @description Thymeleaf template processing with user-controlled input can lead to server-side template injection
 * @kind path-problem
 * @problem.severity error
 * @id java/thymeleaf-ssti
 * @tags security
 *       external/cwe/cwe-094
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

module ThymeleafInjectionConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    source instanceof RemoteFlowSource
  }

  predicate isSink(DataFlow::Node sink) {
    // Thymeleaf TemplateEngine.process() with user-controlled template name
    exists(MethodCall mc |
      mc.getMethod().hasName("process") and
      mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("org.thymeleaf", "ITemplateEngine") and
      sink.asExpr() = mc.getArgument(0)
    )
    or
    // Thymeleaf StringTemplateResolver or ClassLoaderTemplateResolver with user input
    exists(MethodCall mc |
      mc.getMethod().hasName("parseExpression") and
      mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("org.thymeleaf.standard.expression", "IStandardExpressionParser") and
      sink.asExpr() = mc.getAnArgument()
    )
  }
}

module ThymeleafInjectionFlow = TaintTracking::Global<ThymeleafInjectionConfig>;
import ThymeleafInjectionFlow::PathGraph

from ThymeleafInjectionFlow::PathNode source, ThymeleafInjectionFlow::PathNode sink
where ThymeleafInjectionFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "Thymeleaf template injection from $@.", source.getNode(), "user input"

/**
 * @name JNDI injection via user-controlled input
 * @description JNDI lookup with user-controlled names can trigger remote class loading
 * @kind path-problem
 * @problem.severity error
 * @id java/jndi-injection
 * @tags security
 *       external/cwe/cwe-094
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

module JndiInjectionConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    source instanceof RemoteFlowSource
  }

  predicate isSink(DataFlow::Node sink) {
    exists(MethodCall mc |
      mc.getMethod().hasName("lookup") and
      mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("javax.naming", "Context") and
      sink.asExpr() = mc.getArgument(0)
    )
  }
}

module JndiInjectionFlow = TaintTracking::Global<JndiInjectionConfig>;
import JndiInjectionFlow::PathGraph

from JndiInjectionFlow::PathNode source, JndiInjectionFlow::PathNode sink
where JndiInjectionFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "JNDI injection from $@.", source.getNode(), "user input"

/**
 * @name SpEL expression evaluation context contains instance-controlled data
 * @description Trace instance registration data (name, status, info) flowing into SpEL evaluation context
 * @kind path-problem
 * @problem.severity error
 * @id java/spel-instance-data-taint
 * @tags security
 *       external/cwe/cwe-917
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.DataFlow

// Source: data coming from registered instance (Registration, InstanceEvent, etc.)
module SpelInstanceTaintConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    // Registration data from the registered instances
    exists(MethodCall mc |
      (
        mc.getMethod().hasName("getName") or
        mc.getMethod().hasName("getServiceUrl") or
        mc.getMethod().hasName("getManagementUrl") or
        mc.getMethod().hasName("getStatus") or
        mc.getMethod().hasName("getInfo")
      ) and
      (
        mc.getMethod().getDeclaringType().hasQualifiedName("de.codecentric.boot.admin.server.domain.values", "Registration") or
        mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("de.codecentric.boot.admin.server.domain.events", "InstanceEvent") or
        mc.getMethod().getDeclaringType().hasQualifiedName("de.codecentric.boot.admin.server.domain.entities", "Instance")
      ) and
      source.asExpr() = mc
    )
  }

  predicate isSink(DataFlow::Node sink) {
    // SpEL getValue evaluation
    exists(MethodCall mc |
      mc.getMethod().hasName("getValue") and
      mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("org.springframework.expression", "Expression") and
      sink.asExpr() = mc.getAnArgument()
    )
    or
    // SpEL parseExpression
    exists(MethodCall mc |
      mc.getMethod().hasName("parseExpression") and
      mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("org.springframework.expression", "ExpressionParser") and
      sink.asExpr() = mc.getArgument(0)
    )
  }
}

module SpelInstanceTaintFlow = TaintTracking::Global<SpelInstanceTaintConfig>;
import SpelInstanceTaintFlow::PathGraph

from SpelInstanceTaintFlow::PathNode source, SpelInstanceTaintFlow::PathNode sink
where SpelInstanceTaintFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "Instance-controlled data flows to SpEL evaluation from $@.", source.getNode(), "instance data"

/**
 * @name Registration data (name/serviceUrl) taint path to SpEL StandardEvaluationContext
 * @description Trace from HTTP registration endpoint to SpEL evaluation context in notifiers
 * @kind path-problem
 * @problem.severity error
 * @id java/registration-data-to-spel-context
 * @tags security
 *       external/cwe/cwe-917
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

module RegistrationToSpelConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    source instanceof RemoteFlowSource
  }

  predicate isSink(DataFlow::Node sink) {
    // StandardEvaluationContext constructor call - attacker data becomes part of the context
    exists(ClassInstanceExpr newCtx |
      newCtx.getConstructor().getDeclaringType().hasQualifiedName(
        "org.springframework.expression.spel.support", "StandardEvaluationContext"
      ) and
      sink.asExpr() = newCtx.getAnArgument()
    )
    or
    // Map.put with the instance/event object
    exists(MethodCall putCall |
      putCall.getMethod().hasName("put") and
      putCall.getEnclosingCallable().getDeclaringType().getPackage().getName().matches("de.codecentric.boot.admin.server.notify%") and
      sink.asExpr() = putCall.getArgument(1)
    )
  }
}

module RegistrationToSpelFlow = TaintTracking::Global<RegistrationToSpelConfig>;
import RegistrationToSpelFlow::PathGraph

from RegistrationToSpelFlow::PathNode source, RegistrationToSpelFlow::PathNode sink
where RegistrationToSpelFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "Registration data from $@ reaches SpEL evaluation context.", source.getNode(), "HTTP request"
